member.example:
Bind the AudioSource priority property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourcePriorityBinder _priority;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _priority;
    }


Bind the AudioSource priority property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourcePriorityBinder Priority =>
            new(_audioSource, converter: null);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _priority;
    }

Switch the AudioSource priority between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourcePrioritySwitcherBinder _isHighPriority;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighPriority;
    }


Switch the AudioSource priority between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField] 
        private int _highPriority;
        
        [SerializeField] 
        private int _lowPriority;
        
        private AudioSourcePrioritySwitcherBinder IsHighPriority => new(
            _audioSource, _highPriority, _lowPriority);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighPriority;
    }
